"use client";
import { useState } from "react";
import Link from "next/link";

export default function TemperaturePage() {
  const [insight, setInsight] = useState("Select a year to see AI insights.");
  const [loading, setLoading] = useState(false);

  const fetchTemperatureInsights = async (year: string, anomaly: string) => {
    setLoading(true);
    setInsight("Analyzing climate data...");
    try {
      const res = await fetch("/api/temperature-coach", {
        method: "POST",
        body: JSON.stringify({ year, anomaly }),
      });
      const data = await res.json();
      setInsight(data.insight || data.error);
    } catch (err) {
      setInsight("Failed to fetch insights.");
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-black text-white p-10">
      <Link href="/" className="text-gray-400 hover:text-white mb-6 inline-block">← Back to Home</Link>
      <h1 className="text-4xl font-bold text-red-500 mb-6">Global Temperature Rise</h1>
      
      {/* Placeholder for your visual graph */}
      <div className="h-64 bg-gray-900 border border-gray-800 rounded-xl mb-6 flex items-center justify-center text-gray-500">
        [Year-Wise Line Graph Component Goes Here]
      </div>

      <button 
        onClick={() => fetchTemperatureInsights("2023", "1.18")}
        disabled={loading}
        className="bg-red-600 hover:bg-red-500 px-6 py-3 rounded-lg font-bold mb-6 transition-colors disabled:opacity-50"
      >
        Analyze 2023 Data
      </button>

      <div className="p-6 bg-red-950/30 border border-red-500/30 rounded-xl">
        <h3 className="font-bold text-red-400 mb-2">✨ Gemini 2.5 Climate Analysis</h3>
        <p className="whitespace-pre-line leading-relaxed">{insight}</p>
      </div>
    </div>
  );
}